import pickle

import jaxley as jx


def generate_cell(swc):
    print(f"Loading SWC file: {swc}")
    cell = jx.read_swc(
        swc, ncomp=1, min_radius=0, assign_groups=False, backend="custom"
    )
    print(f"SWC loaded. Cell has {len(cell.nodes)} branches")

    cell.compute_compartment_centers()
    cell.initialize()

    print("Loading section lookup table...")
    with open("sec_lu.pkl", "rb") as f:
        sec_lu = pickle.load(f)

    print(f"Section lookup table shape: {sec_lu.shape}")
    print(f"Section lookup data type: {sec_lu.dtype}")

    # Convert to integer if needed
    if sec_lu.dtype != int:
        sec_lu = sec_lu.astype(int)

    assert len(cell.nodes) == len(sec_lu), f"Mismatch: {len(cell.nodes)} branches vs {len(sec_lu)} lookup entries"

    print("Assigning sections to groups...")

    # Create mapping dictionaries first
    section_groups = {}
    compartment_counts = {}

    for i in range(len(cell.nodes)):
        section_type = int(sec_lu[i, 0])
        ncomp = int(sec_lu[i, 1])

        if section_type == 0:
            group_name = "soma"
        elif section_type == 1:
            group_name = "dend"
        elif section_type == 2:
            group_name = "AH"
        elif section_type == 3:
            group_name = "SOCB"
        elif section_type == 4:
            group_name = "NR"
        elif section_type == 5:
            group_name = "axon"
        else:
            print(f"Warning: Unknown section type {section_type} for branch {i}")
            continue

        section_groups[i] = group_name
        compartment_counts[i] = max(1, min(ncomp, 20))  # Limit to reasonable range

        if i % 20 == 0:
            print(f"  Processed {i}/{len(cell.nodes)} branches...")

    print("Applying groups and compartment counts...")
    # Apply all groups and compartment counts
    for i, group_name in section_groups.items():
        try:
            cell.branch(i).add_to_group(group_name)
            cell.branch(i).set_ncomp(compartment_counts[i])
        except Exception as e:
            print(f"Warning: Could not process branch {i} ({group_name}): {e}")

    print("Computing compartment centers and initializing...")
    cell.compute_compartment_centers()
    cell.initialize()

    print(f"Final cell has {len(cell.nodes)} compartments")
    return cell
EOF
